"use client";

import { useEffect } from "react";

interface AdPlaceholderProps {
    className?: string;
    slot?: string;
    responsive?: boolean;
    format?: string;
    width?: number | string;
    height?: number | string;
    label?: string;
}

export function AdPlaceholder({ className, slot, responsive = true, format, width, height, label }: AdPlaceholderProps) {
    useEffect(() => {
        try {
            ((window as any).adsbygoogle = (window as any).adsbygoogle || []).push({});
        } catch (e) {
            // AdSense not loaded yet or ad blocker active
        }
    }, []);

    return (
        <ins
            className={`adsbygoogle block overflow-hidden ${className || ""}`}
            style={{
                display: "block",
                width: width || "100%",
                height: height || "auto",
            }}
            data-ad-client="ca-pub-9381303427467084"
            data-ad-slot={slot}
            data-ad-format={format || (responsive ? "auto" : undefined)}
            data-full-width-responsive={responsive ? "true" : undefined}
            aria-label={label}
        />
    );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { cn } from "@/lib/utils";
import { buttonVariants } from "@/components/ui/button";
import { Menu, X } from "lucide-react";
import { Button } from "@/components/ui/button";

import { EXAMS } from "@/lib/exam-config";

interface SidebarProps extends React.HTMLAttributes<HTMLDivElement> { }

export function ExamSidebar({ className, ...props }: SidebarProps) {
    const pathname = usePathname();
    const [isOpen, setIsOpen] = useState(false);

    // Close sidebar on route change (mobile)
    useEffect(() => {
        setIsOpen(false);
    }, [pathname]);

    const SidebarContent = () => (
        <div className="space-y-4 py-4 h-full">
            <div className="px-3 py-2">
                <div className="flex items-center justify-between mb-4 px-4">
                    <h2 className="text-lg font-semibold tracking-tight">
                        Exam Tools
                    </h2>
                </div>
                <p className="mb-4 px-4 text-sm text-muted-foreground">
                    Select an exam to resize
                </p>
                <div className="space-y-1">
                    {Object.values(EXAMS).map((exam) => {
                        const href = `/resize/${exam.id}`;
                        const isActive = pathname === href;
                        return (
                            <Link
                                key={exam.id}
                                href={href}
                                className={cn(
                                    buttonVariants({ variant: isActive ? "secondary" : "ghost" }),
                                    "w-full justify-start whitespace-normal h-auto py-3 text-sm leading-tight hover:bg-muted/50",
                                    isActive && "bg-secondary hover:bg-secondary font-medium"
                                )}
                            >
                                {exam.title}
                            </Link>
                        );
                    })}
                </div>
            </div>
        </div>
    );

    return (
        <>
            {/* Mobile Floating Bubble Trigger */}
            <div className="lg:hidden fixed left-0 top-1/2 -translate-y-1/2 z-[40]">
                <Button
                    variant="default"
                    size="icon"
                    className="rounded-l-none rounded-r-md h-24 w-8 shadow-xl border-l-0 bg-primary text-primary-foreground hover:bg-primary/90 transition-all active:scale-95 flex items-center justify-center p-0"
                    onClick={() => setIsOpen(true)}
                >
                    <Menu className="h-6 w-6 rotate-90" />
                    <span className="sr-only">Open Sidebar</span>
                </Button>
            </div>

            {/* Mobile Overlay & Drawer */}
            {isOpen && (
                <div
                    className="fixed inset-0 z-50 bg-black/50 lg:hidden backdrop-blur-sm"
                    onClick={() => setIsOpen(false)}
                />
            )}
            <div
                className={cn(
                    "fixed inset-y-0 left-0 z-[60] w-64 bg-background border-r transition-transform duration-300 ease-in-out lg:hidden overflow-y-auto overscroll-contain",
                    isOpen ? "translate-x-0" : "-translate-x-full"
                )}
            >
                <div className="flex justify-end p-2">
                    <Button variant="ghost" size="icon" onClick={() => setIsOpen(false)}>
                        <X className="h-4 w-4" />
                    </Button>
                </div>
                <SidebarContent />
            </div>

            {/* Desktop Sidebar */}
            <div className={cn("hidden lg:block pb-12 border-r bg-background/50 backdrop-blur-sm no-scrollbar overflow-y-auto", className)} {...props}>
                <SidebarContent />
            </div>
        </>
    );
}

"use client"

import * as React from "react"
import { Moon, Sun } from "lucide-react"
import { useTheme } from "next-themes"

import Link from "next/link"
