"use client";

import { useState, useMemo, useEffect, useRef } from "react";
import Link from "next/link";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { ArrowRight, Search, X } from "lucide-react";
import { EXAMS, ExamPageConfig, ToolType } from "@/lib/exam-config";
import { AdPlaceholder } from "@/components/AdPlaceholder";
import { GraduationCap, Scissors, FileCheck, TrainFront, Camera } from "lucide-react";

// Helper to get icon (duplicated from page.tsx, could be moved to utils but fine here)
const getIcon = (id: string) => {
    if (id.includes('upsc')) return GraduationCap;
    if (id.includes('ssc')) return Scissors;
    if (id.includes('ibps')) return FileCheck;
    if (id.includes('rrb')) return TrainFront;
    return Camera;
}

export function ToolsGrid() {
    const [searchQuery, setSearchQuery] = useState("");
    const [showSuggestions, setShowSuggestions] = useState(false);
    const wrapperRef = useRef<HTMLDivElement>(null);

    // Convert EXAMS object to array
    const allExams = useMemo(() => Object.values(EXAMS), []);

    // Filter exams based on search query
    const filteredExams = useMemo(() => {
        if (!searchQuery.trim()) return allExams;
        const query = searchQuery.toLowerCase();
        return allExams.filter((exam) =>
            exam.title.toLowerCase().includes(query) ||
            exam.id.toLowerCase().includes(query) ||
            exam.tools.some(t => t.title.toLowerCase().includes(query))
        );
    }, [searchQuery, allExams]);

    // Suggestions logic (limit to top 5)
    const suggestions = useMemo(() => {
        if (!searchQuery.trim()) return [];
        return filteredExams.slice(0, 5);
    }, [filteredExams, searchQuery]);

    // Close suggestions on click outside
    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
                setShowSuggestions(false);
            }
        }
        document.addEventListener("mousedown", handleClickOutside);
        return () => {
            document.removeEventListener("mousedown", handleClickOutside);
        };
    }, []);

    return (
        <div className="space-y-8">
            {/* Search Bar Section */}
            <div ref={wrapperRef} className="relative max-w-2xl mx-auto">
                <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-muted-foreground" />
                    <Input
                        type="text"
                        placeholder="Search exams (e.g. UPSC, SSC, GATE)..."
                        className="pl-10 pr-10 h-12 text-lg bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 shadow-sm focus-visible:ring-primary"
                        value={searchQuery}
                        onChange={(e) => {
                            setSearchQuery(e.target.value);
                            setShowSuggestions(true);
                        }}
                        onFocus={() => setShowSuggestions(true)}
                    />
                    {searchQuery && (
                        <button
                            onClick={() => {
                                setSearchQuery("");
                                setShowSuggestions(false);
                            }}
                            className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                        >
                            <X className="h-5 w-5" />
                        </button>
                    )}
                </div>

                {/* Autocomplete Suggestions */}
                {showSuggestions && suggestions.length > 0 && (
                    <div className="absolute top-full left-0 right-0 mt-2 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-lg shadow-xl z-50 overflow-hidden">
                        <ul className="py-1">
                            {suggestions.map((exam) => (
                                <li key={exam.id}>
                                    <button
                                        className="w-full text-left px-4 py-3 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors flex items-center gap-3"
                                        onClick={() => {
                                            setSearchQuery(exam.title);
                                            setShowSuggestions(false);
                                        }}
                                    >
                                        <div className="p-1.5 rounded-full bg-primary/10 text-primary">
                                            {(() => {
                                                const Icon = getIcon(exam.id);
                                                return <Icon className="w-4 h-4" />
                                            })()}
                                        </div>
                                        <div>
                                            <p className="font-medium text-sm text-foreground">{exam.title}</p>
                                        </div>
                                    </button>
                                </li>
                            ))}
                        </ul>
                    </div>
                )}
            </div>

            {/* Results Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 max-w-6xl mx-auto">
                {filteredExams.length > 0 ? (
                    filteredExams.map((exam, index) => {
                        const Icon = getIcon(exam.id);
                        return (
                            <div key={exam.id} className="contents">
                                <Card className="hover:shadow-xl transition-all hover:-translate-y-1 border-t-4 border-t-primary/20 bg-white dark:bg-slate-950 dark:border-slate-800">
                                    <CardHeader>
                                        <div className="flex items-center gap-3 mb-2">
                                            <div className="p-3 bg-primary/5 rounded-xl text-primary">
                                                <Icon className="w-6 h-6" />
                                            </div>
                                            <CardTitle className="text-lg line-clamp-1">{exam.id.toUpperCase()}</CardTitle>
                                        </div>
                                        <CardDescription className="line-clamp-2 min-h-[40px]">{exam.title}</CardDescription>
                                    </CardHeader>
                                    <CardContent className="space-y-4">
                                        <div className="text-sm text-gray-500 bg-slate-50 dark:bg-slate-900 p-2 rounded">
                                            <span className="font-semibold block mb-1">Includes:</span>
                                            <ul className="list-disc list-inside">
                                                {exam.tools.slice(0, 2).map((t, i) => (
                                                    <li key={i}>{t.title}</li>
                                                ))}
                                                {exam.tools.length > 2 && <li>+ {exam.tools.length - 2} more</li>}
                                            </ul>
                                        </div>
                                        <Button asChild className="w-full bg-slate-900 hover:bg-slate-800 text-white dark:bg-primary dark:text-primary-foreground">
                                            <Link href={`/resize/${exam.id}`}>
                                                Open {exam.id.toUpperCase()} Tools <ArrowRight className="w-4 h-4 ml-2" />
                                            </Link>
                                        </Button>
                                    </CardContent>
                                </Card>

                                {/* Mobile Ad: Between every card */}
                                {index < filteredExams.length - 1 && (
                                    <div className="md:hidden col-span-1 py-4">
                                        <AdPlaceholder slot="3830647642" className="w-full h-[90px]" label={`Ad Space (Mobile ${index + 1})`} />
                                    </div>
                                )}

                                {/* Ad Logic (Simplified for client component) */}
                                {(index + 1) % 3 === 0 && (
                                    <div className="hidden lg:block col-span-3 py-4">
                                        <AdPlaceholder slot="3830647642" className="w-full h-[90px]" label={`Ad Space (Row ${(index + 1) / 3})`} />
                                    </div>
                                )}
                            </div>
                        );
                    })
                ) : (
                    <div className="col-span-full text-center py-12">
                        <p className="text-muted-foreground text-lg">No exams found matching "{searchQuery}"</p>
                        <Button variant="link" onClick={() => setSearchQuery("")}>Clear Search</Button>
                    </div>
                )}
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { RefreshCw } from "lucide-react";

export function AgeCalculator() {
    const [dob, setDob] = useState("");
    const [targetDate, setTargetDate] = useState(new Date().toISOString().split('T')[0]);
    const [result, setResult] = useState<string | null>(null);

    const calculateAge = () => {
        if (!dob) return;

        const birthDate = new Date(dob);
        const onDate = new Date(targetDate);

        let years = onDate.getFullYear() - birthDate.getFullYear();
        let months = onDate.getMonth() - birthDate.getMonth();
        let days = onDate.getDate() - birthDate.getDate();

        if (days < 0) {
            months--;
            // Get days in previous month
            const prevMonth = new Date(onDate.getFullYear(), onDate.getMonth(), 0);
            days += prevMonth.getDate();
        }

        if (months < 0) {
            years--;
            months += 12;
        }

        setResult(`You are ${years} Years, ${months} Months, and ${days} Days old.`);
    }

    return (
        <Card className="w-full border-2 border-blue-100 shadow-sm bg-white">
            <CardHeader className="bg-blue-50/50 border-b border-blue-100">
                <CardTitle className="text-xl text-blue-900">Sarkari Age Calculator</CardTitle>
                <CardDescription>Calculate your exact age for exam eligibility.</CardDescription>
            </CardHeader>
            <CardContent className="p-6 min-h-[300px] flex flex-col items-center justify-center space-y-8">

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 w-full max-w-lg">
                    <div className="space-y-2">
                        <Label htmlFor="dob">Date of Birth</Label>
                        <Input
                            id="dob"
                            type="date"
                            value={dob}
                            onChange={(e) => setDob(e.target.value)}
                            className="h-12 text-lg"
                        />
                    </div>
                    <div className="space-y-2">
                        <Label htmlFor="target">Calculate Age As Of</Label>
                        <Input
                            id="target"
                            type="date"
                            value={targetDate}
                            onChange={(e) => setTargetDate(e.target.value)}
                            className="h-12 text-lg"
                        />
                    </div>
                </div>

                <Button size="lg" className="w-full max-w-xs bg-blue-600 hover:bg-blue-700 text-lg py-6" onClick={calculateAge}>
                    Calculate Age
                </Button>

                {result && (
                    <div className="mt-8 text-center animate-in fade-in zoom-in duration-300">
                        <h3 className="text-3xl font-bold text-blue-900 bg-blue-50 px-6 py-4 rounded-xl border border-blue-100 inline-block">
                            {result}
                        </h3>
                    </div>
                )}
            </CardContent>
        </Card>
    );
}

"use client";

import { useState, useCallback, useEffect } from "react";
import Image from "next/image";
import Cropper from "react-easy-crop";
// heic2any imported dynamically
import { Area } from "react-easy-crop";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Slider } from "@/components/ui/slider";
import { Input } from "@/components/ui/input";
import { Checkbox } from "@/components/ui/checkbox";
import { Label } from "@/components/ui/label";
import { getCroppedCanvas, resizeCanvas, addDateToPhoto, compressToTargetSize, applyBlackInkFilter, enhanceLegibility } from "@/lib/image-processing";
import { Upload, Download, RefreshCw, Wand2, Droplets } from "lucide-react";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { PrivacyBadge } from "@/components/PrivacyBadge";
import { AffiliateLinks } from "@/components/AffiliateLinks";

// config from lib/exam-config
interface WizardProps {
    title: string;
    config: {
        width?: number;
        height?: number;
        aspect?: number;
        minKB?: number;
        maxKB?: number;
        features?: {
            dateOnPhoto?: boolean;
            nameAndDateOnPhoto?: boolean;
            forceSquare?: boolean;
            isSignature?: boolean;
            isDeclaration?: boolean;
            isThumb?: boolean;
            blackInkOnly?: boolean;
            enhanceLegibility?: boolean;
        };
    };
    affiliateLinks?: {
        label: string;
        url: string;
        note?: string;
    }[];
}

export function ExamPhotoWizard({ title, config, affiliateLinks }: WizardProps) {
    const [imageSrc, setImageSrc] = useState<string | null>(null);
    const [crop, setCrop] = useState({ x: 0, y: 0 });
    const [zoom, setZoom] = useState(1);

    // State for Target KB input (default to maxKB)
    const [targetKB, setTargetKB] = useState(config.maxKB || 50);

    // State for Date & Name
    const [addDate, setAddDate] = useState(config.features?.dateOnPhoto || config.features?.nameAndDateOnPhoto || false);
    const [dateValue, setDateValue] = useState(new Date().toLocaleDateString('en-CA')); // YYYY-MM-DD

    const [nameValue, setNameValue] = useState("");

    // State for Filters
    const [applyBlackInk, setApplyBlackInk] = useState(false);
    const [applyLegibility, setApplyLegibility] = useState(config.features?.enhanceLegibility || false);

    const [croppedAreaPixels, setCroppedAreaPixels] = useState<Area | null>(null);
    const [finalImage, setFinalImage] = useState<string | null>(null);
    const [fileSize, setFileSize] = useState<string | null>(null);
    const [processing, setProcessing] = useState(false);
    const [warningMsg, setWarningMsg] = useState<string | null>(null);

    // Update defaults if config changes
    useEffect(() => {
        setTargetKB(config.maxKB || 50);
        setAddDate(config.features?.dateOnPhoto || config.features?.nameAndDateOnPhoto || false);
        setApplyLegibility(config.features?.enhanceLegibility || false);
        setApplyBlackInk(false); // Default off unless user interacts, or maybe logic demands it? Prompt says "show switch"
    }, [config]);

    const onCropComplete = useCallback((croppedArea: Area, croppedAreaPixels: Area) => {
        setCroppedAreaPixels(croppedAreaPixels);
    }, []);

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files.length > 0) {
            let file = e.target.files[0];

            // HEIC/HEIF Support
            if (file.type === "image/heic" || file.name.toLowerCase().endsWith(".heic")) {
                setWarningMsg("Converting HEIC image... please wait.");
                try {
                    // Dynamically import heic2any to save bandwidth for non-HEIC users
                    const heic2any = (await import("heic2any")).default;

                    const convertedBlob = await heic2any({
                        blob: file,
                        toType: "image/jpeg",
                    });
                    const blob = Array.isArray(convertedBlob) ? convertedBlob[0] : convertedBlob;
                    file = new File([blob], file.name.replace(/\.heic$/i, ".jpg"), { type: "image/jpeg" });
                    setWarningMsg(null);
                } catch (err) {
                    console.error("HEIC conversion failed", err);
                    setWarningMsg("Error: Could not convert HEIC image. Please try a JPG.");
                    return;
                }
            }

            const reader = new FileReader();
            reader.onload = (ev) => {
                setImageSrc(ev.target?.result as string);
                setFinalImage(null);
                setZoom(1);
                setWarningMsg(null);
            };
            reader.readAsDataURL(file);
        }
    };

    const handleGenerate = async () => {
        if (!imageSrc || !croppedAreaPixels) return;

        setProcessing(true);
        setWarningMsg(null);

        try {
            // 1. Crop
            let canvas = await getCroppedCanvas(imageSrc, croppedAreaPixels);

            // 2. Resize
            const targetWidth = config.width || 400;
            const targetHeight = config.height || 400;
            canvas = resizeCanvas(canvas, targetWidth, targetHeight);

            // 3. Apply Filters
            if (applyBlackInk) {
                applyBlackInkFilter(canvas);
            }
            if (applyLegibility) {
                enhanceLegibility(canvas);
            }

            // 4. Draw Date / Name (if enabled)
            if ((config.features?.dateOnPhoto || config.features?.nameAndDateOnPhoto) && addDate) {
                const [yyyy, mm, dd] = dateValue.split('-');
                const formattedDate = `${dd}-${mm}-${yyyy}`;

                let dateText = `DOP: ${formattedDate}`;
                const nameText = config.features?.nameAndDateOnPhoto ? nameValue : undefined;

                addDateToPhoto(canvas, dateText, nameText);
            }

            // 5. Compress to Target KB
            // Use user input targetKB, constrained by config.minKB ??
            const effectiveMaxKB = targetKB;

            const result = await compressToTargetSize(canvas, effectiveMaxKB);

            // Create URL
            const url = URL.createObjectURL(result.blob);
            setFinalImage(url);
            setFileSize(result.sizeKB.toFixed(1) + " KB");

            if (result.warning) {
                setWarningMsg(result.warning);
            }

        } catch (e) {
            console.error(e);
            setWarningMsg("Error: Failed to generate image.");
        } finally {
            setProcessing(false);
        }
    };

    const downloadImage = () => {
        if (finalImage) {
            const link = document.createElement("a");
            link.href = finalImage;

            // Smart filename: ExamResizer_Exam_Title_Date.jpg
            const safeTitle = title.replace(/[^a-z0-9]/gi, '_').replace(/_+/g, '_').toLowerCase();
            const dateStr = new Date().toISOString().split('T')[0];
            link.download = `ExamResizer_${safeTitle}_${dateStr}.jpg`;

            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
        }
    };

    const reset = () => {
        // setImageSrc(null); // Keep image to allow re-edit
        // Reset everything else to default state
        setFinalImage(null);
        setZoom(1);
        setCrop({ x: 0, y: 0 }); // Reset position to center
        setWarningMsg(null);
    };

    const aspect = config.aspect || (config.features?.forceSquare ? 1 : (config.width && config.height ? config.width / config.height : 1));

    return (
        <Card className="w-full border-2 border-primary/10 shadow-lg bg-card text-card-foreground">
            <CardHeader className="bg-muted/50 border-b">
                <CardTitle className="text-xl flex items-center justify-between">
                    <div>
                        {title}
                    </div>
                    {imageSrc && (
                        <div className="flex gap-2">
                            <Button variant="ghost" size="sm" onClick={() => {
                                setImageSrc(null);
                                setFinalImage(null);
                                setZoom(1);
                                setWarningMsg(null);
                            }}>
                                <Upload className="w-4 h-4 mr-1" /> New Photo
                            </Button>
                            <Button variant="ghost" size="sm" onClick={reset}>
                                <RefreshCw className="w-4 h-4 mr-1" /> Reset Crop
                            </Button>
                        </div>
                    )}
                </CardTitle>
            </CardHeader>

            <CardContent className="p-6">
                {!imageSrc ? (
                    <div className="border-2 border-dashed border-muted-foreground/25 rounded-xl p-12 flex flex-col items-center justify-center text-center space-y-4 hover:bg-muted/50 transition-colors cursor-pointer relative group">
                        <input
                            type="file"
                            className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                            accept="image/*"
                            onChange={handleFileChange}
                        />
                        <div className="bg-primary/10 p-4 rounded-full text-primary group-hover:scale-110 transition-transform">
                            <Upload className="w-8 h-8" />
                        </div>
                        <div>
                            <p className="font-semibold text-lg">Click to Upload Photo</p>
                            <p className="text-sm text-muted-foreground">Supports JPG, PNG</p>
                        </div>
                        <PrivacyBadge />
                    </div>
                ) : !finalImage ? (
                    <div className="space-y-8">
                        <div className="space-y-8">
                            {/* 1. Editor Section (Full Width) */}
                            <div className="space-y-6 max-w-2xl mx-auto w-full">
                                <div className="relative h-[450px] w-full bg-slate-900 rounded-2xl overflow-hidden shadow-2xl ring-1 ring-slate-800">
                                    <Cropper
                                        image={imageSrc}
                                        crop={crop}
                                        zoom={zoom}
                                        aspect={aspect}
                                        onCropChange={setCrop}
                                        onCropComplete={onCropComplete}
                                        onZoomChange={setZoom}
                                        showGrid={true}
