"use client";

import { useState, useRef, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Download, RefreshCw } from "lucide-react";
import { compressToTargetSize } from "@/lib/image-processing";
import { AffiliateLinks } from "@/components/AffiliateLinks";

interface DeclarationProps {
    config: {
        minKB?: number;
        maxKB?: number;
    };
    affiliateLinks?: { label: string; url: string; note?: string }[];
}

export function HandwrittenDeclaration({ config, affiliateLinks }: DeclarationProps) {
    const [name, setName] = useState("");
    const [finalImage, setFinalImage] = useState<string | null>(null);
    const [fileSize, setFileSize] = useState<string | null>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);

    // Load custom font
    useEffect(() => {
        const font = new FontFace("Caveat", "url(https://fonts.gstatic.com/s/caveat/v17/Wnz6HAc5bAfYB2Q7ZjDglvV5.woff2)");
        font.load().then((loadedFont) => {
            document.fonts.add(loadedFont);
        }).catch(err => console.log("Font load error", err));
    }, []);

    const generateDeclaration = async () => {
        if (!name.trim()) {
            alert("Please enter your name.");
            return;
        }

        const width = 800;
        const height = 400;
        const canvas = document.createElement("canvas");
        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext("2d");
        if (!ctx) return;

        // 1. Background (Paper Texture / Off-white with noise)
        ctx.fillStyle = "#f8f8f8";
        ctx.fillRect(0, 0, width, height);

        // Add noise
        for (let i = 0; i < 5000; i++) {
            const x = Math.random() * width;
            const y = Math.random() * height;
            ctx.fillStyle = Math.random() > 0.5 ? "rgba(0,0,0,0.05)" : "rgba(255,255,255,0.5)";
            ctx.fillRect(x, y, 1, 1);
        }

        // 2. Text Content
        const text = `I, ${name}, hereby declare that all the information submitted by me in the application form is correct, true and valid. I will present the supporting documents as and when required.`;

        // 3. Draw Text
        ctx.fillStyle = "black"; // Black Ink
        // Use Caveat if loaded, else Cursive/Handwriting fallback
        ctx.font = "32px 'Caveat', 'Brush Script MT', cursive";
        ctx.textBaseline = "top";

        const margin = 40;
        const maxWidth = width - (margin * 2);
        const lineHeight = 50;
        let y = 60;

        const words = text.split(" ");
        let line = "";

        for (let n = 0; n < words.length; n++) {
            const testLine = line + words[n] + " ";
            const metrics = ctx.measureText(testLine);
            const testWidth = metrics.width;
            if (testWidth > maxWidth && n > 0) {
                // Add jitter for handwriting effect
                const jitterX = (Math.random() - 0.5) * 2;
                const jitterY = (Math.random() - 0.5) * 2;
                ctx.fillText(line, margin + jitterX, y + jitterY);
                line = words[n] + " ";
                y += lineHeight;
            } else {
                line = testLine;
            }
        }
        ctx.fillText(line, margin, y);

        // 4. Compress
        try {
            const result = await compressToTargetSize(canvas, config.maxKB || 100);
            const url = URL.createObjectURL(result.blob);
            setFinalImage(url);
            setFileSize(result.sizeKB.toFixed(1) + " KB");
        } catch (e) {
            console.error(e);
            alert("Compression failed");
        }
    };

    const downloadImage = () => {
        if (finalImage) {
            const link = document.createElement("a");
            link.href = finalImage;
            link.download = `ibps-declaration-${name.replace(/\s+/g, '-').toLowerCase()}.jpg`;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
        }
    };

    return (
        <Card className="w-full border-2 border-primary/10 shadow-lg">
            <CardHeader className="bg-muted/50 border-b">
                <CardTitle>IBPS/SBI Handwritten Declaration Generator</CardTitle>
            </CardHeader>
            <CardContent className="p-6 space-y-6">
                {!finalImage ? (
                    <div className="space-y-4">
                        <div className="space-y-2">
                            <Label>Enter Your Name</Label>
                            <Input
                                value={name}
                                onChange={(e) => setName(e.target.value)}
                                placeholder="e.g. John Doe"
                            />
                            <p className="text-sm text-muted-foreground">
                                This will generate the standard declaration text with your name in a handwritten font.
                            </p>
                        </div>

                        <Button onClick={generateDeclaration} className="w-full" size="lg">
                            Generate Declaration
                        </Button>
                    </div>
                ) : (
                    <div className="space-y-6 text-center">
                        <div className="border border-slate-200 rounded-lg overflow-hidden shadow-sm">
                            <img src={finalImage} alt="Declaration" className="w-full h-auto" />
                        </div>
                        <div className="space-y-2">
                            <p className="text-lg font-medium text-green-600">Generated! ({fileSize})</p>
                            <div className="flex gap-4 justify-center">
                                <Button variant="outline" onClick={() => setFinalImage(null)}>
                                    <RefreshCw className="mr-2 h-4 w-4" /> Create New
                                </Button>
                                <Button onClick={downloadImage} className="bg-green-600 hover:bg-green-700">
                                    <Download className="mr-2 h-4 w-4" /> Download JPG
                                </Button>
                            </div>
                            <AffiliateLinks links={affiliateLinks} title="Declaration Generator" />
                        </div>
                    </div>
                )}
            </CardContent>
        </Card>
    );
}

"use client";

import { useState } from "react";
import jsPDF from "jspdf";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Upload, FileDown, Trash2, FileText } from "lucide-react";
import { compressToTargetSize, loadImage } from "@/lib/image-processing";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { AffiliateLinks } from "@/components/AffiliateLinks";

interface ImageToPDFProps {
    config?: {
        minKB?: number;
        maxKB?: number;
    };
    affiliateLinks?: { label: string; url: string; note?: string }[];
}

export function ImageToPDF({ config, affiliateLinks }: ImageToPDFProps) {
    const [images, setImages] = useState<{ src: string; file: File; id: string }[]>([]);
    const [processing, setProcessing] = useState(false);
    const [pdfUrl, setPdfUrl] = useState<string | null>(null);
    const [pdfSize, setPdfSize] = useState<string | null>(null);
    const [error, setError] = useState<string | null>(null);

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files) {
            const newImages = Array.from(e.target.files).map(file => ({
                src: URL.createObjectURL(file), // Provide preview
                file,
                id: Math.random().toString(36).substr(2, 9)
            }));
            setImages(prev => [...prev, ...newImages]);
            setPdfUrl(null);
            setError(null);
        }
    };

    const removeImage = (id: string) => {
        setImages(prev => prev.filter(img => img.id !== id));
        setPdfUrl(null);
    };

    const generatePDF = async () => {
        if (images.length === 0) return;

        setProcessing(true);
        setError(null);

        try {
            const doc = new jsPDF();
            const maxTotalSizeKB = config?.maxKB || 300; // Default 300KB constraint from prompt

            // Calculate budget per image (naive approach: split evenly, or compress individually)
            // Better approach: Compress each image to a reasonable high quality, check PDF size.
            // If too big, aggressively compress.

            // For now, let's try to compress each image to ensure they fit. 
            // If we have N images, and max is 300KB. 
            // Let's target (Max - 50KB overhead) / N per image.
            const overhead = 20; // KB
            const targetPerImage = Math.floor((maxTotalSizeKB - overhead) / images.length);

            // Ensure at least 20KB per image
            const safeTarget = Math.max(targetPerImage, 20);

            for (let i = 0; i < images.length; i++) {
                const imgItem = images[i];
                const img = await loadImage(imgItem.src);

                // Create a canvas to compress
                const canvas = document.createElement("canvas");
                canvas.width = img.width;
                canvas.height = img.height;
                const ctx = canvas.getContext("2d");
                if (!ctx) continue;
                ctx.drawImage(img, 0, 0);

                // Compress
                const compressed = await compressToTargetSize(canvas, safeTarget);

                // Convert blob to base64 for jspdf
                const base64 = await new Promise<string>((resolve) => {
                    const reader = new FileReader();
                    reader.onloadend = () => resolve(reader.result as string);
                    reader.readAsDataURL(compressed.blob);
                });

                const imgProps = doc.getImageProperties(base64);

                // Scale to fit A4 page (210 x 297 mm)
                const pdfWidth = doc.internal.pageSize.getWidth();
                const pdfHeight = doc.internal.pageSize.getHeight();

                // Margin
                const margin = 10;
                const availableWidth = pdfWidth - (margin * 2);
                const availableHeight = pdfHeight - (margin * 2);

                const ratio = Math.min(availableWidth / imgProps.width, availableHeight / imgProps.height);
                const w = imgProps.width * ratio;
                const h = imgProps.height * ratio;

                const x = (pdfWidth - w) / 2;
                const y = margin;

                if (i > 0) doc.addPage();
                doc.addImage(base64, 'JPEG', x, y, w, h);
            }

            const pdfBlob = doc.output('blob');
            const sizeKB = pdfBlob.size / 1024;

            if (sizeKB > maxTotalSizeKB) {
                setError(`PDF size (${sizeKB.toFixed(0)} KB) exceeds limit (${maxTotalSizeKB} KB). Try fewer images.`);
            }

            setPdfUrl(URL.createObjectURL(pdfBlob));
            setPdfSize(`${sizeKB.toFixed(1)} KB`);

        } catch (err) {
            console.error(err);
            setError("Failed to generate PDF");
        } finally {
            setProcessing(false);
        }
    };

    return (
        <Card className="w-full border-2 border-dashed border-primary/20 shadow-sm">
            <CardHeader>
                <CardTitle className="flex items-center gap-2">
                    <FileText className="w-5 h-5 text-red-500" />
                    Image to PDF Converter
                </CardTitle>
                <CardDescription>
                    Convert images to a single PDF document. Auto-compressed to {config?.maxKB || 300} KB.
                </CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">

                {/* Upload Area */}
                <div className="flex items-center justify-center w-full">
                    <label className="flex flex-col items-center justify-center w-full h-32 border-2 border-gray-300 border-dashed rounded-lg cursor-pointer bg-gray-50 dark:hover:bg-bray-800 dark:bg-gray-700 hover:bg-gray-100 dark:border-gray-600 dark:hover:border-gray-500 dark:hover:bg-gray-600">
                        <div className="flex flex-col items-center justify-center pt-5 pb-6">
                            <Upload className="w-8 h-8 mb-4 text-gray-500 dark:text-gray-400" />
                            <p className="mb-2 text-sm text-gray-500 dark:text-gray-400"><span className="font-semibold">Click to upload</span> or drag and drop</p>
                            <p className="text-xs text-gray-500 dark:text-gray-400">JPG, PNG (MAX. 5MB)</p>
                        </div>
                        <input type="file" className="hidden" multiple accept="image/*" onChange={handleFileUpload} />
                    </label>
                </div>

                {/* Image Preview List */}
                {images.length > 0 && (
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        {images.map((img, idx) => (
                            <div key={img.id} className="relative group aspect-[3/4] rounded-lg overflow-hidden border bg-black/5">
                                <img src={img.src} alt={`Page ${idx + 1}`} className="object-contain w-full h-full" />
                                <button
                                    onClick={() => removeImage(img.id)}
                                    className="absolute top-1 right-1 bg-red-500 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"
                                >
                                    <Trash2 className="w-4 h-4" />
                                </button>
                                <div className="absolute bottom-0 left-0 right-0 bg-black/60 text-white text-xs p-1 text-center">
                                    Page {idx + 1}
                                </div>
                            </div>
                        ))}
                    </div>
                )}

                {/* Error */}
                {error && (
                    <Alert variant="destructive">
                        <AlertTitle>Error</AlertTitle>
                        <AlertDescription>{error}</AlertDescription>
                    </Alert>
                )}

                {/* Actions */}
                <div className="flex justify-end gap-3 border-t pt-4">
                    {images.length > 0 && !pdfUrl && (
                        <Button onClick={generatePDF} disabled={processing} className="w-full md:w-auto">
                            {processing ? "Generating..." : "Generate PDF"}
                        </Button>
                    )}

                    {pdfUrl && (
                        <div className="w-full space-y-3">
                            <div className="flex items-center justify-between p-3 bg-green-50 text-green-800 rounded-lg border border-green-200">
                                <span className="font-medium flex items-center gap-2">
                                    <FileText className="w-4 h-4" />
                                    PDF Ready
                                </span>
                                <span className="text-sm font-bold">{pdfSize}</span>
                            </div>
                            <Button className="w-full bg-green-600 hover:bg-green-700" asChild>
                                <a href={pdfUrl} download="sarkari-document.pdf">
                                    <FileDown className="w-4 h-4 mr-2" /> Download PDF
                                </a>
                            </Button>
                            <Button variant="ghost" onClick={() => setPdfUrl(null)} className="w-full text-sm">
                                Generate Another
                            </Button>
                            <AffiliateLinks links={affiliateLinks} title="Image to PDF" />
                        </div>
                    )}
                </div>

            </CardContent>
        </Card>
    );
}

"use client";

import { useState } from "react";
import Image from "next/image";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Upload, Download, Loader2 } from "lucide-react";
import { createPostcard } from "@/lib/image-processing";

import { AffiliateLinks } from "@/components/AffiliateLinks";

interface PostcardMakerProps {
    config?: {
        width?: number;
        height?: number;
        minKB?: number;
        maxKB?: number;
        aspect?: number;
        label?: string;
        features?: {
            dateOnPhoto?: boolean;
            nameAndDateOnPhoto?: boolean;
            forceSquare?: boolean;
            isSignature?: boolean;
            isDeclaration?: boolean;
            blackInkOnly?: boolean;
            enhanceLegibility?: boolean;
        };
    };
    affiliateLinks?: { label: string; url: string; note?: string }[];
}

export function PostcardMaker({ config, affiliateLinks }: PostcardMakerProps) {
    const [imageSrc, setImageSrc] = useState<string | null>(null);
    const [result, setResult] = useState<string | null>(null);
    const [processing, setProcessing] = useState(false);

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files?.[0]) {
            const reader = new FileReader();
            reader.onload = (ev) => setImageSrc(ev.target?.result as string);
            reader.readAsDataURL(e.target.files[0]);
            setResult(null);
        }
    };

    const generatePostcard = async () => {
        if (!imageSrc) return;
        setProcessing(true);
        try {
            const postcardDataUrl = await createPostcard(imageSrc);
            setResult(postcardDataUrl);
        } catch (e) {
            console.error(e);
            alert("Failed to create postcard.");
        } finally {
            setProcessing(false);
        }
    };

    const download = () => {
        if (result) {
            const link = document.createElement('a');
            link.href = result;
            link.download = `neet-postcard-${Date.now()}.jpg`;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
        }
    };

    return (
        <Card className="w-full border-2 border-primary/10 bg-card">
            <CardHeader>
                <CardTitle className="text-lg">Step 2: Postcard Size Generator (4x6 inch)</CardTitle>
                <CardDescription>Convert your passport photo to a 4x6 inch Postcard size with margins.</CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
                {!imageSrc ? (
                    <div className="border-2 border-dashed rounded-xl p-12 flex flex-col items-center justify-center text-center cursor-pointer hover:bg-muted/50 relative">
                        <input type="file" accept="image/*" className="absolute inset-0 opacity-0 cursor-pointer" onChange={handleFileChange} />
                        <Upload className="w-10 h-10 text-muted-foreground mb-4" />
                        <p className="font-medium">Upload Passport Photo</p>
                    </div>
                ) : (
                    <div className="flex flex-col items-center space-y-4">
                        <div className="bg-slate-100 p-2 rounded relative w-full h-32 flex justify-center">
                            <Image
                                src={imageSrc}
                                alt="Source"
                                width={200}
                                height={200}
                                className="h-full w-auto object-contain"
                                unoptimized
                            />
                        </div>
                        <Button onClick={generatePostcard} disabled={processing} className="w-full">
                            {processing ? <Loader2 className="animate-spin mr-2" /> : null}
                            Generate Postcard
                        </Button>
                    </div>
                )}

                {result && (
                    <div className="space-y-4 animate-in slide-in-from-bottom-4 pt-4 border-t w-full flex flex-col items-center">
                        <p className="text-center font-semibold text-green-600">Postcard Ready!</p>
                        <div className="border p-2 bg-white shadow-sm flex justify-center">
                            <Image
                                src={result}
                                alt="Postcard"
                                width={300}
                                height={450}
                                className="max-h-[400px] w-auto"
                                unoptimized
                            />
                        </div>
                        <div className="flex gap-4 w-full">
                            <Button variant="outline" onClick={() => { setImageSrc(null); setResult(null); }} className="flex-1">
                                Start Over
                            </Button>
                            <Button onClick={download} className="flex-1 bg-green-600 hover:bg-green-700">
                                <Download className="mr-2" /> Download 4x6 inch JPG
                            </Button>
                        </div>
                        <AffiliateLinks links={affiliateLinks} title="Postcard Generator" />
                    </div>
                )}
            </CardContent>
        </Card>
    );
}

"use client";

import { useState } from "react";
import Image from "next/image";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Upload, Download, Loader2 } from "lucide-react";
import { joinSignatures } from "@/lib/image-processing";
import { AffiliateLinks } from "@/components/AffiliateLinks";

interface SignatureJoinerProps {
    config?: {
        width?: number;
        height?: number;
        minKB?: number;
        maxKB?: number;
        aspect?: number;
        label?: string;
        features?: {
            dateOnPhoto?: boolean;
            nameAndDateOnPhoto?: boolean;
            forceSquare?: boolean;
            isSignature?: boolean;
            isDeclaration?: boolean;
            blackInkOnly?: boolean;
            enhanceLegibility?: boolean;
        };
    };
    affiliateLinks?: { label: string; url: string; note?: string }[];
}

export function SignatureJoiner({ config, affiliateLinks }: SignatureJoinerProps) {
    const [files, setFiles] = useState<(string | null)[]>([null, null, null]);
    const [processing, setProcessing] = useState(false);
    const [result, setResult] = useState<string | null>(null);

    const handleFileChange = (index: number) => (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            const file = e.target.files[0];
            const reader = new FileReader();
            reader.onload = (ev) => {
                const newFiles = [...files];
                newFiles[index] = ev.target?.result as string;
                setFiles(newFiles);
                setResult(null);
            };
            reader.readAsDataURL(file);
        }
    };

    const handleGenerate = async () => {
        if (files.some(f => !f)) {
            alert("Please upload all 3 signatures.");
            return;
        }

        setProcessing(true);
        try {
            const validFiles = files.filter((f): f is string => !!f);
            const mergedImage = await joinSignatures(validFiles);
            setResult(mergedImage);
        } catch (error) {
            console.error(error);
            alert("Failed to merge signatures.");
        } finally {
            setProcessing(false);
        }
    };

    const handleDownload = () => {
        if (result) {
            // Check if we need to enforce size limits from config?
            // The prompt says "Export". It doesn't explicitly ask for compression here, 
            // but the config has minKB/maxKB.
            // For now, we download as is, which usually is small enough for signatures.

            const link = document.createElement('a');
            link.href = result;
            link.download = `upsc-triple-sig-${Date.now()}.jpg`;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
        }
    };

    return (
        <Card className="w-full border-2 border-primary/10 bg-card">
            <CardHeader>
                <CardTitle className="text-lg">Triple Signature Uploader (Vertical)</CardTitle>
                <CardDescription>Upload top, middle, and bottom signatures.</CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    {["Top Signature", "Middle Signature", "Bottom Signature"].map((label, idx) => (
                        <div key={idx} className="space-y-2">
                            <Label>{label}</Label>
                            <div className="border-2 border-dashed rounded-lg p-4 h-32 flex flex-col items-center justify-center text-center cursor-pointer hover:bg-muted/50 relative bg-slate-50 dark:bg-slate-900 dark:border-slate-800 transition-colors">
                                <input type="file" accept="image/*" className="absolute inset-0 opacity-0 cursor-pointer" onChange={handleFileChange(idx)} />
                                {files[idx] ? (
                                    <div className="relative w-full h-full">
                                        <Image
                                            src={files[idx]!}
                                            alt={`Sig ${idx + 1}`}
                                            fill
                                            className="object-contain"
                                            unoptimized
                                        />
                                    </div>
                                ) : (
                                    <div className="text-muted-foreground">
                                        <Upload className="w-6 h-6 mx-auto mb-2 opacity-50" />
                                        <span className="text-xs font-medium">Click to Upload</span>
                                    </div>
                                )}
                            </div>
                        </div>
                    ))}
                </div>

                <Button
                    className="w-full"
                    size="lg"
                    disabled={files.some(f => !f) || processing}
                    onClick={handleGenerate}
                >
                    {processing ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : null}
                    {processing ? "Merging..." : "Merge Signatures"}
                </Button>

                {result && (
                    <div className="flex flex-col items-center space-y-4 animate-in fade-in pt-4 border-t">
                        <Label className="text-green-600 font-bold">Preview Result</Label>
                        <div className="border p-2 bg-white dark:bg-slate-900 shadow-sm flex justify-center">
                            <Image
                                src={result}
                                alt="Merged"
                                width={350}
                                height={500}
                                className="max-h-[300px] w-auto"
                                unoptimized
                            />
                        </div>

                        <div className="flex gap-4 w-full justify-center">
                            <Button variant="outline" onClick={() => setResult(null)}>Edit Again</Button>
                            <Button onClick={handleDownload} className="bg-green-600 hover:bg-green-700">
                                <Download className="w-4 h-4 mr-2" /> Download Merged JPG
                            </Button>
                        </div>

                        <AffiliateLinks links={affiliateLinks} title="Signature Merger" />
                    </div>
                )}
            </CardContent>
        </Card>
    );
}

